def single_linkage_clustering(X, n_clusters=2):
    """
    X: list of points
    Returns cluster labels for n_clusters.
    """
    n    = len(X)
    labels = list(range(n))  # each point is its own cluster

    def dist(a, b):
        return sum((ai-bi)**2 for ai,bi in zip(a,b))**0.5

    def cluster_dist(c1, c2, points_in):
        """Single linkage: minimum distance between any two points in c1 and c2."""
        return min(
            dist(X[i], X[j])
            for i in points_in[c1]
            for j in points_in[c2]
        )

    points_in = {i: [i] for i in range(n)}
    clusters  = set(range(n))

    while len(clusters) > n_clusters:
        best_d = float('inf')
        merge_a = merge_b = -1
        cluster_list = sorted(clusters)
        for i in range(len(cluster_list)):
            for j in range(i+1, len(cluster_list)):
                ca, cb = cluster_list[i], cluster_list[j]
                d = cluster_dist(ca, cb, points_in)
                if d < best_d:
                    best_d, merge_a, merge_b = d, ca, cb
        # Merge merge_b into merge_a
        points_in[merge_a] += points_in.pop(merge_b)
        clusters.remove(merge_b)
        for p in ___________:
            labels[p] = merge_a
    # Remap labels to 0..n_clusters-1
    mapping = {c: i for i, c in enumerate(sorted(clusters))}
    return [mapping[labels[i]] for i in range(n)]
